<template><div class="workspace-page"><section class="welcome-panel"><div><p>预约履约与报告生产中心</p><h2>{{summary.institution?.name||'机构运营总览'}}</h2><span>机构只处理本机构预约与报告，不可浏览用户日常测量或其他健康资料。</span></div><el-button type="primary" @click="router.push({name:'org-reports'})">进入体检管理</el-button></section><section class="metric-grid" v-loading="loading"><article v-for="m in metrics" :key="m.label" class="metric-card"><span class="metric-icon">{{m.icon}}</span><div><small>{{m.label}}</small><strong>{{m.value}}</strong><p>{{m.note}}</p></div></article></section><el-alert title="确认到检后才可建立报告；报告锁定后不可修改，提交归档后不可撤下。" type="info" show-icon :closable="false"/></div></template><script setup>import{computed,onMounted,ref}from"vue";import{useRouter}from"vue-router";import{fetchOrgDashboard}from"../../api/dashboards";const router=useRouter(),summary=ref({}),loading=ref(false);const metrics=computed(()=>{const a=summary.value.appointment_status_counts||{};return[{label:"未履约",value:a.unfulfilled||0,icon:"约",note:"可确认到检或标记失效"},{label:"待上传报告",value:a.awaiting_report||0,icon:"传",note:"需要完成报告归档"},{label:"已履约",value:a.fulfilled||0,icon:"成",note:"报告已永久归档"},{label:"待审套餐",value:summary.value.pending_package_review_count||0,icon:"审",note:"等待管理员处理"}]});onMounted(async()=>{loading.value=true;try{summary.value=(await fetchOrgDashboard()).data.summary||{}}finally{loading.value=false}});</script>
